// Extracted from original portfolio index.html
// PARTICLES
const canvas = document.getElementById('particles');
const ctx = canvas.getContext('2d');
let pts = [];
function resize(){ canvas.width=innerWidth; canvas.height=innerHeight; }
function mkPts(){
  pts=[];
  const n=Math.floor((canvas.width*canvas.height)/9000);
  for(let i=0;i<n;i++) pts.push({x:Math.random()*canvas.width,y:Math.random()*canvas.height,r:Math.random()*1.5+0.3,dx:(Math.random()-.5)*0.2,dy:(Math.random()-.5)*0.2,a:Math.random()*0.5+0.15});
}
function draw(){
  ctx.clearRect(0,0,canvas.width,canvas.height);
  pts.forEach(p=>{
    ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
    ctx.fillStyle=`rgba(111,236,184,${p.a})`;ctx.fill();
    p.x+=p.dx;p.y+=p.dy;
    if(p.x<0||p.x>canvas.width)p.dx*=-1;
    if(p.y<0||p.y>canvas.height)p.dy*=-1;
  });
  requestAnimationFrame(draw);
}
resize();mkPts();draw();
window.addEventListener('resize',()=>{resize();mkPts();});

// HUD COUNTERS
function hudCount(numId, finalText, pipIds, delay) {
  const el = document.getElementById(numId);
  if (el) el.textContent = finalText;
  setTimeout(() => {
    pipIds.forEach((id, i) => {
      setTimeout(() => {
        const p = document.getElementById(id);
        if (p) p.classList.add('active');
      }, i * 120);
    });
  }, delay);
}
function initHudCounters(){
  hudCount('hud-n1', '3+', ['hp1a','hp1b','hp1c'], 1000);
  hudCount('hud-n2', '1yr', ['hp2a'], 1300);
  hudCount('hud-n3', '2', ['hp3a','hp3b'], 1600);
}
if (document.readyState === 'complete') {
  initHudCounters();
} else {
  window.addEventListener('load', initHudCounters);
  setTimeout(initHudCounters, 500);
}

// SCROLL REVEAL
let currentPage='home';
let observer=null;
function initReveal(){
  if(observer)observer.disconnect();
  const els = document.querySelectorAll('#page-'+currentPage+' .reveal');
  observer=new IntersectionObserver(entries=>{
    entries.forEach(e=>{ if(e.isIntersecting){ e.target.classList.add('visible'); observer.unobserve(e.target); } });
  },{threshold:0.05, rootMargin:'0px 0px -20px 0px'});
  els.forEach(el=>observer.observe(el));
  setTimeout(()=>{ els.forEach(el=>el.classList.add('visible')); }, 2500);
}

// NAV + SCROLL HINT
window.addEventListener('scroll',()=>{
  document.getElementById('navbar').classList.toggle('scrolled',scrollY>20);

},{passive:true});

// PAGE SWITCH
function showPage(id,el){
  currentPage=id;
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  document.querySelectorAll('.reveal').forEach(r=>r.classList.remove('visible'));
  document.getElementById('page-'+id).classList.add('active');
  document.querySelectorAll('.nav-links a').forEach(a=>a.classList.remove('active'));
  if(el)el.classList.add('active');
  window.scrollTo(0,0);
  setTimeout(initReveal,80);
  // Reinit map when experience tab opens
  if(id === 'experience'){
    setTimeout(function(){
      if(typeof initMap === 'function') initMap();
      // Extra invalidateSize call after render settles
      setTimeout(function(){
        var mapEl = document.getElementById('operator-map');
        if(mapEl && mapEl._leaflet_map){
          mapEl._leaflet_map.invalidateSize(true);
        }
      }, 500);
    }, 250);
  }
}

// ── HOME LAB MODAL ──
function openLabModal(){
  var modal = document.getElementById('lab-modal');
  if(modal){ modal.style.display='flex'; }
}
function closeLabModal(){
  var modal = document.getElementById('lab-modal');
  if(modal){ modal.style.display='none'; }
  document.body.style.overflow='';
  document.documentElement.style.overflow='';
  // Re-trigger map size if on experience page
  setTimeout(function(){
    var mapEl = document.getElementById('operator-map');
    if(mapEl && mapEl._leaflet_map){
      mapEl._leaflet_map.invalidateSize(true);
    }
  }, 100);
}
document.addEventListener('keydown', function(e){
  if(e.key === 'Escape') closeLabModal();
});

function handleSubmit(e){
  e.preventDefault();
  var form = e.target;
  var data = new FormData(form);
  fetch('https://formspree.io/f/xvzdgldg', {
    method: 'POST',
    body: data,
    headers: { 'Accept': 'application/json' }
  }).then(function(response){
    if(response.ok){
      document.getElementById('form-success').style.display = 'block';
      document.getElementById('form-error').style.display = 'none';
      form.reset();
    } else {
      document.getElementById('form-error').style.display = 'block';
      document.getElementById('form-success').style.display = 'none';
    }
  }).catch(function(){
    document.getElementById('form-error').style.display = 'block';
    document.getElementById('form-success').style.display = 'none';
  });
}

setTimeout(initReveal,300);


// ── MESSAGES UI ──
function showMsg(contact){
  document.querySelectorAll('.msg-thread-content').forEach(function(t){ t.style.display='none'; });
  document.getElementById('thread-'+contact).style.display='flex';
  document.getElementById('thread-'+contact).style.flexDirection='column';
  document.getElementById('thread-'+contact).style.gap='10px';

  var names = {rogue:'ROGUE // Fixer · Afterlife', corpo:'MILITECH HR // Corporate Recruiter', judy:'JUDY // Contact'};
  document.getElementById('msg-contact-name').textContent = names[contact] || contact.toUpperCase();

  document.querySelectorAll('.msg-contact').forEach(function(c){
    c.style.background='transparent';
    c.style.borderLeft='2px solid transparent';
  });
  event.currentTarget.style.background='rgba(245,230,66,0.06)';
  event.currentTarget.style.borderLeft='2px solid var(--yellow)';
}

function sendMsg(){
  var input = document.getElementById('msg-input');
  var text = input.value.trim();
  if(!text) return;
  var thread = document.getElementById('msg-thread').querySelector('.msg-thread-content:not([style*="display:none"])') 
    || document.getElementById('thread-rogue');
  var now = new Date();
  var time = now.getHours()+':'+String(now.getMinutes()).padStart(2,'0');
  var msg = document.createElement('div');
  msg.style.cssText='display:flex;flex-direction:column;align-items:flex-end;gap:2px;margin-top:4px;';
  msg.innerHTML='<div style="font-size:8px;color:#444440;margin-bottom:2px;">V // '+time+'</div><div style="background:#0d1a0d;border:1px solid rgba(111,236,184,0.2);border-radius:8px 2px 8px 8px;padding:8px 12px;max-width:85%;font-size:11px;color:#c8c8c0;line-height:1.6;">'+text+'</div>';
  thread.appendChild(msg);
  input.value='';
  // Scroll to bottom
  var threadDiv = document.getElementById('msg-thread');
  threadDiv.scrollTop = threadDiv.scrollHeight;
  // Auto reply after delay
  setTimeout(function(){
    var reply = document.createElement('div');
    reply.style.cssText='display:flex;flex-direction:column;align-items:flex-start;gap:2px;margin-top:4px;';
    reply.innerHTML='<div style="font-size:8px;color:#444440;margin-bottom:2px;">SYSTEM // '+time+'</div><div style="background:#1a1508;border:1px solid rgba(245,230,66,0.2);border-radius:2px 8px 8px 8px;padding:8px 12px;max-width:85%;font-size:11px;color:#c8c8c0;line-height:1.6;">// Message received. Routing to K.Padilla. Response incoming via email.</div>';
    thread.appendChild(reply);
    threadDiv.scrollTop = threadDiv.scrollHeight;
  }, 1200);
}

