// ── SPLASH SCREEN ──
(function(){
  var canvas = document.getElementById('splash-canvas');
  var ctx = canvas.getContext('2d');
  var chars = '09';
  var fontSize = 14;
  var drops = [];
  var animId;

  function resize(){
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    var cols = Math.floor(canvas.width / fontSize);
    drops = [];
    for(var i = 0; i < cols; i++){
      drops[i] = Math.random() * -50;
    }
  }

  function drawRain(){
    ctx.fillStyle = 'rgba(8,8,8,0.05)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    for(var i = 0; i < drops.length; i++){
      var char = chars[Math.floor(Math.random() * chars.length)];
      var brightness = Math.random();
      if(brightness > 0.92){
        ctx.fillStyle = '#ffffff';
      } else if(brightness > 0.7){
        ctx.fillStyle = '#6FECB8';
      } else {
        ctx.fillStyle = 'rgba(111,236,184,' + (0.1 + brightness * 0.5) + ')';
      }
      ctx.font = fontSize + 'px Share Tech Mono, monospace';
      ctx.fillText(char, i * fontSize, drops[i] * fontSize);
      if(drops[i] * fontSize > canvas.height && Math.random() > 0.975){
        drops[i] = 0;
      }
      drops[i]++;
    }
    animId = requestAnimationFrame(drawRain);
  }

  resize();
  window.addEventListener('resize', resize);
  drawRain();

  // ── SHARED GLITCH — logo and splash name ──
  function makeGlitcher(base,ghostR,ghostW,opts){
    opts=opts||{};
    var bf=opts.baseFilter||'drop-shadow(0 0 12px rgba(111,236,184,0.4))';
    var isLogo=opts.isLogo||false;
    function glitch(){
      if(!base)return;
      var v=Math.random();
      if(isLogo)base.style.opacity=(0.15+Math.random()*0.2).toString();
      if(v>0.7){
        var tx=(Math.random()-0.5)*14,ty=(Math.random()-0.5)*6,sk=(Math.random()-0.5)*8;
        base.style.transform='translate('+tx+'px,'+ty+'px) skewX('+sk+'deg)';
        base.style.filter='drop-shadow(0 0 16px rgba(111,236,184,0.7)) brightness('+(1.5+Math.random()*2)+')';
        if(ghostR){ghostR.style.opacity=(0.4+Math.random()*0.5).toString();ghostR.style.transform='translate('+(tx+Math.random()*10)+'px,'+ty+'px)';ghostR.style.clipPath='inset('+Math.floor(Math.random()*60)+'% 0 '+Math.floor(Math.random()*40)+'% 0)';}
        if(ghostW){ghostW.style.opacity=(0.3+Math.random()*0.5).toString();ghostW.style.transform='translate('+(tx-Math.random()*10)+'px,'+ty+'px)';ghostW.style.clipPath='inset('+Math.floor(Math.random()*40+20)+'% 0 '+Math.floor(Math.random()*30)+'% 0)';}
        setTimeout(function(){
          if(base){base.style.transform='translate(0,0) skewX(0)';base.style.filter=bf;if(isLogo)base.style.opacity='0.25';}
          if(ghostR)ghostR.style.opacity='0';
          if(ghostW)ghostW.style.opacity='0';
        },60+Math.random()*80);
      } else if(v>0.4){
        base.style.transform='translate('+((Math.random()-0.5)*4)+'px,0)';
        setTimeout(function(){if(base)base.style.transform='translate(0,0)';},40);
      } else {
        base.style.transform='translate(0,0)';
        base.style.filter=bf;
      }
      setTimeout(glitch,80+Math.random()*200);
    }
    setTimeout(glitch,opts.delay||500);
  }
  (function(){
    makeGlitcher(document.getElementById('logo-base'),document.getElementById('logo-ghost-r'),document.getElementById('logo-ghost-w'),{isLogo:true,delay:500});
  })();
  (function(){
    var n=document.getElementById('splash-name');
    if(!n)return;
    makeGlitcher(n.querySelector('.name-base'),n.querySelector('.name-ghost-r'),n.querySelector('.name-ghost-w'),{baseFilter:'none',isLogo:false,delay:2200});
  })();

  function dismissSplash(){
    var splash = document.getElementById('splash');
    if(!splash) return;

    // Cleaner exit: remove the old "JACKING IN" glitch/slice effect.
    // Recruiters should move into the portfolio smoothly instead of waiting through
    // another high-motion transition after the landing screen.
    document.body.style.overflow = 'hidden';
    document.body.style.touchAction = 'none';
    splash.classList.add('fade-out');
    cancelAnimationFrame(animId);

    setTimeout(function(){
      splash.style.display = 'none';
      document.body.style.overflow = '';
      document.body.style.touchAction = '';
    }, 450);
  }

  // After 1.5s reveal name/title, then run the loading bar, then show click prompt
  setTimeout(function(){
    var name = document.getElementById('splash-name');
    var title = document.getElementById('splash-title');
    var barWrap = document.getElementById('splash-bar-wrap');
    var bar = document.getElementById('splash-bar');
    var pct = document.getElementById('splash-pct');
    var btn = document.getElementById('splash-enter');
    if(name){ name.style.opacity = '1'; }
    if(title){ title.style.opacity = '1'; }
    if(barWrap){ barWrap.style.opacity = '1'; }
    if(pct){ pct.style.opacity = '1'; }

    setTimeout(function(){
      if(bar){ bar.style.width = '100%'; }
      var count = 0;
      var interval = setInterval(function(){
        count += 2;
        if(count >= 100){
          count = 100;
          clearInterval(interval);
          if(pct){ pct.textContent = 'SYSTEM READY'; }
          // Show the enter button
          setTimeout(function(){
            if(btn){ btn.style.opacity = '1'; btn.style.transform = 'translateY(0)'; }
          }, 300);
        } else {
          if(pct){ pct.textContent = count + '% LOADING...'; }
        }
      }, 18);
    }, 300);
  }, 1500);

  // Click anywhere or button to enter
  document.getElementById('splash').addEventListener('click', function(){
    var btn = document.getElementById('splash-enter');
    if(btn && btn.style.opacity === '1'){
      dismissSplash();
    }
  });
})();
